# Base types module: interface, abstract class, struct, enum

interface IDrawable:
    def draw(self) -> str: ...

@abstract
class Shape(IDrawable):
    position: Point

    def __init__(self, pos: Point):
        self.position = pos

    @abstract
    def area(self) -> float: ...

    @virtual
    def describe(self) -> str:
        return "A shape"

    def draw(self) -> str:
        return f"Drawing at ({self.position.x}, {self.position.y})"

struct Point:
    x: float
    y: float

    def __init__(self, x: float, y: float):
        self.x = x
        self.y = y

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

