# Concrete shape implementations - demonstrates cross-module inheritance
from models import Shape, Point, Color

class Circle(Shape):
    radius: float

    def __init__(self, pos: Point, radius: float):
        super().__init__(pos)
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle(r={self.radius})"

class Rectangle(Shape):
    width: float
    height: float

    def __init__(self, pos: Point, width: float, height: float):
        super().__init__(pos)
        self.width = width
        self.height = height

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle({self.width}x{self.height})"

def make_colored_circle(color: Color, radius: float) -> Circle:
    p: Point = Point(0.0, 0.0)
    return Circle(p, radius)

