# Utility functions - demonstrates cross-module imports
from models import Point, Color
from shapes import Circle, Rectangle

def create_unit_circle() -> Circle:
    origin: Point = Point(0.0, 0.0)
    return Circle(origin, 1.0)

def create_square(corner: Point, size: float) -> Rectangle:
    return Rectangle(corner, size, size)

PI_CONST: float = 3.14159

def sum_areas(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total
